head.b:skin:
/* ----------------------------------------------
    PREMIUM NEWS PORTAL THEME
    Modern Glassmorphism + Smooth Animations
----------------------------------------------- */
:root {
    --primary: #e74c3c;
    --primary-light: #ff6b5b;
    --primary-dark: #c0392b;
    --secondary: #0f172a;
    --secondary-light: #1e293b;
    --bg-light: #f0f4f8;
    --surface: #ffffff;
    --surface-glass: rgba(255, 255, 255, 0.95);
    --border: rgba(226, 232, 240, 0.6);
    --text-dark: #0f172a;
    --text-muted: #64748b;
    --text-light: #94a3b8;
    --gradient-primary: linear-gradient(135deg, #e74c3c 0%, #c0392b 100%);
    --gradient-dark: linear-gradient(135deg, #0f172a 0%, #1e293b 100%);
    --gradient-glass: linear-gradient(135deg, rgba(255,255,255,0.9), rgba(255,255,255,0.95));
    --shadow-sm: 0 2px 8px rgba(0,0,0,0.04), 0 1px 2px rgba(0,0,0,0.03);
    --shadow-md: 0 8px 20px rgba(0,0,0,0.06), 0 2px 4px rgba(0,0,0,0.02);
    --shadow-lg: 0 20px 35px -10px rgba(0,0,0,0.1);
    --shadow-xl: 0 30px 45px -15px rgba(0,0,0,0.15);
    --transition: all 0.35s cubic-bezier(0.4, 0, 0.2, 1);
    --border-radius-sm: 12px;
    --border-radius-md: 20px;
    --border-radius-lg: 28px;
    --border-radius-xl: 36px;
}

* { margin: 0; padding: 0; box-sizing: border-box; }

body {
    background: var(--bg-light);
    font-family: 'Inter', 'Hind Siliguri', sans-serif;
    color: var(--text-dark);
    padding-top: 80px;
    line-height: 1.5;
    position: relative;
}

/* Animated Background Pattern */
body::before {
    content: '';
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background-image: radial-gradient(circle at 25% 40%, rgba(231,76,60,0.03) 0%, transparent 50%),
                      radial-gradient(circle at 75% 60%, rgba(15,23,42,0.02) 0%, transparent 50%);
    pointer-events: none;
    z-index: -1;
}

.container { max-width: 1280px; margin: 0 auto; padding: 0 28px; }

/* ========== HEADER ========== */
header {
    background: rgba(255,255,255,0.98);
    backdrop-filter: blur(10px);
    height: 80px;
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    z-index: 1000;
    border-bottom: 1px solid var(--border);
    transition: var(--transition);
}
header.scrolled {
    box-shadow: var(--shadow-lg);
    background: rgba(255,255,255,0.98);
}

.header-flex {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 20px;
    flex-wrap: wrap;
    height: 80px;
}

.logo-area {
    display: flex;
    align-items: center;
    gap: 12px;
}
.logo-icon {
    font-size: 34px;
    background: var(--gradient-primary);
    -webkit-background-clip: text;
    background-clip: text;
    color: transparent;
}
.logo {
    font-size: 28px;
    font-weight: 800;
    text-decoration: none;
    background: linear-gradient(135deg, #0f172a 0%, #334155 100%);
    -webkit-background-clip: text;
    background-clip: text;
    color: transparent;
    letter-spacing: -0.5px;
}
.logo span {
    background: var(--gradient-primary);
    -webkit-background-clip: text;
    background-clip: text;
    color: transparent;
}

/* ========== HERO SECTION - PREMIUM ========== */
.hero {
    background: var(--gradient-dark);
    border-radius: var(--border-radius-xl);
    padding: 60px 40px;
    margin: 30px 0 50px;
    color: white;
    text-align: center;
    position: relative;
    overflow: hidden;
    box-shadow: var(--shadow-xl);
}
.hero::before {
    content: '📰';
    position: absolute;
    font-size: 220px;
    opacity: 0.05;
    bottom: -40px;
    right: -30px;
    pointer-events: none;
}
.hero::after {
    content: '🌐';
    position: absolute;
    font-size: 180px;
    opacity: 0.05;
    top: -50px;
    left: -40px;
    pointer-events: none;
}
.hero-badge {
    display: inline-block;
    background: rgba(255,255,255,0.15);
    backdrop-filter: blur(4px);
    border-radius: 60px;
    padding: 8px 22px;
    font-size: 0.85rem;
    font-weight: 500;
    margin-bottom: 24px;
    letter-spacing: 0.5px;
}
.hero h1 {
    font-size: 3rem;
    font-weight: 800;
    margin-bottom: 16px;
    background: linear-gradient(135deg, #fff, #e2e8f0);
    -webkit-background-clip: text;
    background-clip: text;
    color: transparent;
    letter-spacing: -0.02em;
}
.hero p {
    font-size: 1.15rem;
    opacity: 0.9;
    max-width: 550px;
    margin: 0 auto;
}
.hero-stats {
    display: flex;
    justify-content: center;
    gap: 30px;
    margin-top: 35px;
    flex-wrap: wrap;
}
.hero-stats div {
    background: rgba(255,255,255,0.1);
    backdrop-filter: blur(4px);
    padding: 8px 24px;
    border-radius: 50px;
    font-weight: 600;
    font-size: 0.9rem;
}
.hero-stats i { margin-right: 8px; color: var(--primary-light); }

/* ========== MAIN LAYOUT ========== */
.main-wrapper {
    display: flex;
    flex-wrap: wrap;
    gap: 36px;
    margin-bottom: 60px;
}
.main-content { flex: 2.5; min-width: 0; }
.sidebar-right { flex: 1; min-width: 280px; }

/* ========== CATEGORY SECTIONS ========== */
.category-section {
    margin-bottom: 52px;
    animation: fadeInUp 0.5s ease-out;
}
@keyframes fadeInUp {
    from { opacity: 0; transform: translateY(20px); }
    to { opacity: 1; transform: translateY(0); }
}
.cat-header {
    display: flex;
    align-items: center;
    gap: 14px;
    margin-bottom: 28px;
    padding-left: 20px;
    position: relative;
}
.cat-header::before {
    content: '';
    position: absolute;
    left: 0;
    top: 0;
    bottom: 0;
    width: 5px;
    background: var(--gradient-primary);
    border-radius: 10px;
}
.cat-header i {
    font-size: 1.6rem;
    background: var(--gradient-primary);
    -webkit-background-clip: text;
    background-clip: text;
    color: transparent;
}
.cat-header h2 {
    font-size: 1.8rem;
    font-weight: 700;
    color: var(--secondary);
    margin: 0;
    letter-spacing: -0.3px;
}

/* ========== NEWS CARDS - PREMIUM ========== */
.news-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(190px, 1fr));
    gap: 24px;
}
.news-card {
    background: var(--surface);
    border-radius: var(--border-radius-md);
    padding: 24px 16px 20px;
    text-align: center;
    border: 1px solid var(--border);
    transition: var(--transition);
    cursor: pointer;
    position: relative;
    overflow: hidden;
    backdrop-filter: blur(0px);
}
.news-card::before {
    content: '';
    position: absolute;
    top: 0;
    left: -100%;
    width: 100%;
    height: 4px;
    background: var(--gradient-primary);
    transition: var(--transition);
}
.news-card:hover::before {
    left: 0;
}
.news-card:hover {
    transform: translateY(-8px);
    border-color: transparent;
    box-shadow: var(--shadow-lg);
}
.news-card img {
    width: 60px;
    height: 60px;
    border-radius: 18px;
    margin-bottom: 14px;
    background: #fff;
    padding: 6px;
    object-fit: contain;
    transition: var(--transition);
    box-shadow: var(--shadow-sm);
}
.news-card:hover img {
    transform: scale(1.05);
}
.news-card span {
    display: block;
    font-weight: 700;
    font-size: 0.95rem;
    color: var(--text-dark);
    margin-top: 6px;
}
.news-card small {
    font-size: 0.7rem;
    color: var(--text-muted);
    margin-top: 8px;
    display: block;
    font-weight: 500;
}

/* ========== SIDEBAR WIDGETS ========== */
.sidebar-widget {
    background: var(--surface-glass);
    backdrop-filter: blur(10px);
    border-radius: var(--border-radius-lg);
    border: 1px solid var(--border);
    padding: 24px;
    margin-bottom: 32px;
    transition: var(--transition);
    box-shadow: var(--shadow-md);
}
.sidebar-widget:hover {
    transform: translateY(-3px);
    box-shadow: var(--shadow-lg);
}
.sidebar-widget-title {
    font-size: 1.25rem;
    font-weight: 700;
    background: var(--gradient-primary);
    -webkit-background-clip: text;
    background-clip: text;
    color: transparent;
    display: inline-block;
    padding-bottom: 8px;
    margin-bottom: 20px;
    border-bottom: 2px solid var(--primary-light);
}
.sidebar-list { list-style: none; }
.sidebar-list li {
    margin-bottom: 14px;
    padding: 8px 0 8px 14px;
    border-left: 3px solid var(--border);
    transition: var(--transition);
}
.sidebar-list li:hover {
    border-left-color: var(--primary);
    background: rgba(231,76,60,0.05);
    border-radius: 0 12px 12px 0;
}
.sidebar-list a {
    text-decoration: none;
    color: var(--text-dark);
    font-weight: 500;
    transition: var(--transition);
    display: flex;
    align-items: center;
    gap: 10px;
    cursor: pointer;
}
.sidebar-list a:hover { color: var(--primary); transform: translateX(5px); }
.sidebar-list i { width: 28px; color: var(--primary); font-size: 1.1rem; }

/* ========== MODAL ========== */
.modal-view {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0,0,0,0.96);
    backdrop-filter: blur(12px);
    z-index: 9999;
    display: none;
    flex-direction: column;
    animation: fadeIn 0.3s ease;
}
@keyframes fadeIn {
    from { opacity: 0; }
    to { opacity: 1; }
}
.modal-bar {
    background: var(--secondary-light);
    padding: 16px 28px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    color: #fff;
    flex-wrap: wrap;
    gap: 12px;
}
.modal-bar .site-info {
    display: flex;
    align-items: center;
    gap: 16px;
    flex-wrap: wrap;
}
.open-new-tab-btn {
    background: rgba(255,255,255,0.1);
    border: 1px solid rgba(255,255,255,0.2);
    color: #fff;
    padding: 8px 18px;
    border-radius: 40px;
    cursor: pointer;
    font-size: 0.85rem;
    transition: var(--transition);
    text-decoration: none;
    display: inline-flex;
    align-items: center;
    gap: 8px;
}
.open-new-tab-btn:hover {
    background: var(--primary);
    border-color: var(--primary);
    transform: scale(1.02);
}
iframe#readerFrame {
    flex: 1;
    border: none;
    background: #fff;
    width: 100%;
}
.close-btn {
    background: var(--gradient-primary);
    border: none;
    color: #fff;
    padding: 8px 22px;
    border-radius: 40px;
    cursor: pointer;
    font-weight: 600;
    transition: var(--transition);
}
.close-btn:hover {
    transform: scale(1.02);
    filter: brightness(1.05);
}
.error-message {
    display: none;
    text-align: center;
    padding: 100px 20px;
    background: var(--surface);
    height: 100%;
    flex-direction: column;
    align-items: center;
    justify-content: center;
}
.error-message i { font-size: 72px; color: var(--primary); margin-bottom: 24px; }
.error-message h3 { font-size: 1.8rem; margin-bottom: 16px; color: var(--secondary); }
.error-message p { margin-bottom: 28px; color: var(--text-muted); max-width: 450px; }

/* ========== FOOTER ========== */
footer {
    background: var(--gradient-dark);
    color: #cbd5e1;
    padding: 56px 0 28px;
    margin-top: 40px;
    border-radius: var(--border-radius-xl) var(--border-radius-xl) 0 0;
}
.footer-grid {
    display: flex;
    flex-wrap: wrap;
    gap: 48px;
    justify-content: space-between;
    margin-bottom: 48px;
}
.footer-col { flex: 1; min-width: 180px; }
.footer-logo { font-size: 26px; font-weight: 800; color: white; margin-bottom: 16px; display: inline-block; }
.footer-logo span { color: var(--primary-light); }
.footer-text { opacity: 0.7; font-size: 0.85rem; line-height: 1.6; }
.footer-title { color: white; font-weight: 700; margin-bottom: 20px; border-left: 3px solid var(--primary); padding-left: 14px; font-size: 1.1rem; }
.footer-links { list-style: none; }
.footer-links li { margin-bottom: 12px; }
.footer-links a { color: #cbd5e1; text-decoration: none; transition: var(--transition); font-size: 0.9rem; }
.footer-links a:hover { color: var(--primary-light); padding-left: 6px; }
.copyright {
    text-align: center;
    padding-top: 28px;
    border-top: 1px solid rgba(255,255,255,0.08);
    font-size: 0.8rem;
    color: #94a3b8;
}

/* ========== RESPONSIVE ========== */
@media (max-width: 800px) {
    body { padding-top: 70px; }
    .hero h1 { font-size: 1.8rem; }
    .hero { padding: 40px 24px; }
    .main-wrapper { flex-direction: column; }
    .news-grid { grid-template-columns: repeat(auto-fill, minmax(155px, 1fr)); gap: 16px; }
    .cat-header h2 { font-size: 1.5rem; }
    header { height: auto; }
    body { padding-top: 110px; }
    .header-flex { height: auto; padding: 12px 0; }
}
@media (max-width: 480px) {
    .container { padding: 0 18px; }
    .news-grid { grid-template-columns: repeat(2, 1fr); gap: 14px; }
    .hero-stats { gap: 12px; }
    .hero-stats div { padding: 6px 16px; font-size: 0.75rem; }
}

/* Scroll Animation */
.category-section {
    opacity: 0;
    animation: fadeInUp 0.6s ease-out forwards;
}
.category-section:nth-child(1) { animation-delay: 0.05s; }
.category-section:nth-child(2) { animation-delay: 0.1s; }
.category-section:nth-child(3) { animation-delay: 0.15s; }
.category-section:nth-child(4) { animation-delay: 0.2s; }
.category-section:nth-child(5) { animation-delay: 0.25s; }
.category-section:nth-child(6) { animation-delay: 0.3s; }
.category-section:nth-child(7) { animation-delay: 0.35s; }

body.script:
//
    var currentUrl = '';
    var currentName = '';

    function viewNews(url, name) {
        if (!url) return;
        currentUrl = url;
        currentName = name || 'পত্রিকা';

        var modal = document.getElementById('newsModal');
        var frame = document.getElementById('readerFrame');
        var errorDiv = document.getElementById('iframeError');
        var titleSpan = document.getElementById('activePaper');
        var newTabLink = document.getElementById('openInNewTab');
        var errorLink = document.getElementById('errorOpenLink');

        if (titleSpan) titleSpan.innerHTML = '<i class="fas fa-globe"></i> ' + currentName;
        if (newTabLink) newTabLink.href = url;
        if (errorLink) errorLink.href = url;

        if (errorDiv) errorDiv.style.display = 'none';
        if (frame) {
            frame.style.display = 'block';
            frame.src = url;
        }

        if (modal) modal.style.display = 'flex';
        document.body.style.overflow = 'hidden';
    }

    function closeNews() {
        var modal = document.getElementById('newsModal');
        var frame = document.getElementById('readerFrame');
        var errorDiv = document.getElementById('iframeError');

        if (modal) modal.style.display = 'none';
        if (frame) {
            frame.src = '';
            frame.style.display = 'block';
        }
        if (errorDiv) errorDiv.style.display = 'none';
        document.body.style.overflow = 'auto';
    }

    document.addEventListener('keydown', function(e) {
        if (e.key === 'Escape') {
            var modal = document.getElementById('newsModal');
            if (modal && modal.style.display === 'flex') closeNews();
        }
    });

    var modal = document.getElementById('newsModal');
    if (modal) {
        modal.addEventListener('click', function(e) {
            if (e.target === modal) closeNews();
        });
    }

    // Header scroll effect
    window.addEventListener('scroll', function() {
        var header = document.getElementById('mainHeader');
        if (window.scrollY > 50) {
            header.classList.add('scrolled');
        } else {
            header.classList.remove('scrolled');
        }
    });
//
